// src/Tools.jsx
import React, { useEffect, useMemo, useState } from "react";
import { useNavigate } from "react-router-dom";

const apiBase = "https://prasa-app-yde3.onrender.com";
const green = "#0f9d58";
const lightGreen = "#eaf8f0";

export default function Tools({ employee }) {
  const [travelExpenses, setTravelExpenses] = useState([]);
  const [ticketExpenses, setTicketExpenses] = useState([]);
  const [files, setFiles] = useState([]);
  const [message, setMessage] = useState("");
  const navigate = useNavigate();

  useEffect(() => {
    if (employee?.empld) {
      fetchData();
    }
  }, [employee]);

  const fetchData = async () => {
    try {
      const [tRes, kRes] = await Promise.all([
        fetch(`${apiBase}/travel-expenses?empld=${encodeURIComponent(employee.empld)}`),
        fetch(`${apiBase}/ticket-expenses?empld=${encodeURIComponent(employee.empld)}`),
      ]);
      const [travel, tickets] = await Promise.all([tRes.json(), kRes.json()]);
      setTravelExpenses(travel || []);
      setTicketExpenses(tickets || []);
    } catch (err) {
      console.error("Tools fetch error:", err);
    }
  };

  // Build monthly totals for graph
  const monthlyTotals = useMemo(() => {
    const map = {};
    const add = (dateStr, amount) => {
      if (!dateStr) return;
      const d = new Date(dateStr);
      if (Number.isNaN(d.getTime())) return;
      const key = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(
        2,
        "0"
      )}`;
      map[key] = (map[key] || 0) + Number(amount || 0);
    };

    travelExpenses.forEach((t) => add(t.travel_date, t.amount));
    ticketExpenses.forEach((t) => add(t.ticket_date, t.amount));

    const entries = Object.entries(map).sort((a, b) => (a[0] > b[0] ? 1 : -1));
    return entries;
  }, [travelExpenses, ticketExpenses]);

  const maxTotal =
    monthlyTotals.length === 0
      ? 0
      : Math.max(...monthlyTotals.map(([_, total]) => total));

  // Bill upload (frontend only demo)
  const handleFileChange = (e) => {
    setFiles(Array.from(e.target.files || []));
  };

  const handleFakeUpload = (e) => {
    e.preventDefault();
    if (!files.length) {
      setMessage("Please select at least one file to upload.");
      return;
    }
    // TODO: real upload:
    // const formData = new FormData();
    // files.forEach((f) => formData.append("bills", f));
    // await fetch(`${apiBase}/upload-bills`, { method: "POST", body: formData });
    //
    // Backend would then save to /expense/<empld>/... on the server machine.
    setMessage("✅ Bills ready for upload (frontend demo).");
  };

  // Download CSV report
  const downloadReport = () => {
    const rows = [
      ["Type", "Date", "Purpose", "AssignedTo/FromTo", "Amount"],
      ...travelExpenses.map((t) => [
        "Travel",
        t.travel_date,
        t.purpose,
        `${t.location_from || ""} -> ${t.location_to || ""}`,
        t.amount,
      ]),
      ...ticketExpenses.map((t) => [
        "Ticket",
        t.ticket_date,
        t.purpose,
        t.assigned_to || "",
        t.amount,
      ]),
    ];

    const csvContent = rows
      .map((row) =>
        row.map((cell) => `"${String(cell ?? "").replace(/"/g, '""')}"`).join(",")
      )
      .join("\n");

    const blob = new Blob([csvContent], {
      type: "text/csv;charset=utf-8;",
    });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = `prasa-expense-report-${employee.empld}.csv`;
    link.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div
      style={{
        minHeight: "100vh",
        background: lightGreen,
        padding: 16,
        fontFamily: "Segoe UI",
      }}
    >
      <div
        style={{
          maxWidth: 1000,
          margin: "0 auto",
          background: "#ffffff",
          borderRadius: 16,
          padding: 18,
          boxShadow: "0 6px 20px rgba(0,0,0,0.12)",
        }}
      >
        {/* Back arrow + title */}
        <div
          style={{
            display: "flex",
            alignItems: "center",
            gap: 10,
            marginBottom: 8,
          }}
        >
          <button
            onClick={() => navigate("/profile")}
            style={{
              background: "transparent",
              border: "none",
              color: green,
              fontSize: 16,
              cursor: "pointer",
            }}
          >
            ⬅ Back
          </button>
          <h2 style={{ color: green, margin: 0 }}>Tools</h2>
        </div>

        <p style={{ fontSize: 13, color: "#555", marginBottom: 16 }}>
          Employee: {employee.name} • {employee.empld}
        </p>

        {/* Layout: 3 sections stacked nicely */}
        {/* 1. Monthly Graph */}
        <section style={{ marginBottom: 24 }}>
          <h3 style={{ color: green, marginBottom: 8 }}>Monthly Expense Graph</h3>
          {monthlyTotals.length === 0 ? (
            <p style={{ fontSize: 13 }}>No expense data to show yet.</p>
          ) : (
            <div
              style={{
                borderRadius: 12,
                padding: 12,
                background: "#f9fff9",
                border: `1px solid ${lightGreen}`,
              }}
            >
              <div
                style={{
                  display: "flex",
                  alignItems: "flex-end",
                  gap: 12,
                  height: 200,
                }}
              >
                {monthlyTotals.map(([month, total]) => (
                  <div
                    key={month}
                    style={{
                      flex: 1,
                      display: "flex",
                      flexDirection: "column",
                      alignItems: "center",
                      justifyContent: "flex-end",
                    }}
                  >
                    <div
                      style={{
                        width: "70%",
                        height: maxTotal ? (total / maxTotal) * 160 : 0,
                        borderRadius: 10,
                        background: green,
                        transition: "height 0.3s",
                      }}
                    />
                    <div
                      style={{
                        marginTop: 6,
                        fontSize: 11,
                        textAlign: "center",
                      }}
                    >
                      {month}
                      <br />
                      ₹{total}
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}
        </section>

        {/* 2. Bill Upload */}
        <section style={{ marginBottom: 24 }}>
          <h3 style={{ color: green, marginBottom: 8 }}>Bill Upload</h3>
          <p style={{ fontSize: 12, color: "#555", marginBottom: 6 }}>
            Select your bill PDFs / images here. (Current version is a demo –
            backend can save them into an <b>expense</b> folder on the server.)
          </p>
          <form
            onSubmit={handleFakeUpload}
            style={{
              background: "#fbfff9",
              padding: 12,
              borderRadius: 12,
              border: `1px solid ${lightGreen}`,
            }}
          >
            <input
              type="file"
              multiple
              onChange={handleFileChange}
              style={{ marginBottom: 10 }}
            />
            <button
              type="submit"
              style={{
                padding: 8,
                borderRadius: 10,
                border: "none",
                background: green,
                color: "#ffffff",
                fontWeight: 600,
                cursor: "pointer",
              }}
            >
              Upload Bills (demo)
            </button>
            {files.length > 0 && (
              <div style={{ marginTop: 8, fontSize: 12 }}>
                Selected: {files.map((f) => f.name).join(", ")}
              </div>
            )}
          </form>
        </section>

        {/* 3. Report Download */}
        <section>
          <h3 style={{ color: green, marginBottom: 8 }}>Report Download</h3>
          <p style={{ fontSize: 13, color: "#555" }}>
            Download a CSV summary of your travel and ticket expenses for your
            own offline report.
          </p>
          <button
            onClick={downloadReport}
            style={{
              padding: 10,
              borderRadius: 10,
              border: "none",
              background: green,
              color: "#ffffff",
              fontWeight: 600,
              cursor: "pointer",
            }}
          >
            Download Report (CSV)
          </button>
        </section>

        {message && (
          <div style={{ marginTop: 10, color: green, fontSize: 13 }}>
            {message}
          </div>
        )}
      </div>
    </div>
  );
}
